def starts_with(s: String, prefix: String) -> Int:
    var np = prefix.byte_length()
    if np > s.byte_length():
        return 0
    for i in range(np):
        if String(s[byte=i]) != String(prefix[byte=i]):
            return 0
    return 1

def ends_with(s: String, suffix: String) -> Int:
    var ns = s.byte_length()
    var nf = suffix.byte_length()
    if nf > ns:
        return 0
    for i in range(nf):
        if String(s[byte=ns - nf + i]) != String(suffix[byte=i]):
            return 0
    return 1

def substring_count(s: String, sub: String) -> Int:
    var ns = s.byte_length()
    var nb = sub.byte_length()
    if nb == 0:
        return 0
    var count = 0
    for i in range(ns - nb + 1):
        var ok = True
        for j in range(nb):
            if String(s[byte=i + j]) != String(sub[byte=j]):
                ok = False
                break
        if ok:
            count += 1
    return count

def concat_n(s: String, n: Int) -> String:
    var result = String("")
    for _ in range(n):
        result += s
    return result

def join_with_dash(parts: List[String]) -> String:
    var result = String("")
    for i in range(len(parts)):
        if i > 0:
            result += "-"
        result += parts[i]
    return result

def run_length_encode(s: String) -> String:
    var n = s.byte_length()
    var result = String("")
    var i = 0
    while i < n:
        var c = String(s[byte=i])
        var run = 1
        while i + run < n and String(s[byte=i + run]) == c:
            run += 1
        result += c
        result += String(run)
        i += run
    return result

def count_words(s: String) -> Int:
    var count = 0
    var in_word = False
    for cp_slice in s.codepoint_slices():
        if String(cp_slice) == " ":
            in_word = False
        else:
            if not in_word:
                count += 1
            in_word = True
    return count

def parse_int_checked(s: String) raises -> Int:
    if s.byte_length() == 0:
        raise Error("empty")
    var val = 0
    for cp in s.codepoints():
        var c = Int(cp)
        if c < 48 or c > 57:
            raise Error("non-digit")
        val = val * 10 + (c - 48)
    return val

